function normalizeBrPhoneDigits(raw) {
  let d = String(raw || '').replace(/\D/g, '');
  if (!d) return '';
  if ((d.length === 10 || d.length === 11) && !d.startsWith('55')) d = '55' + d;
  return d;
}

const req = $json || {};
const body = req.body || req;
if (body.phone || req.phone) {
  const src = body.phone ? body : req;
  const digits = normalizeBrPhoneDigits(src.phone || '');
  return [{ json: {
    ...req,
    phone_e164: digits ? `+${digits}` : '',
    message_id: src.message_id ?? `wa-${Date.now()}`,
    text: String(src.text ?? ''),
    contact_name: String(src.contact_name ?? ''),
    has_audio: false,
    evento_valido: true,
    webhook_meta: { mode: 'smoke' },
  }}];
}

const data = body.data || {};
const key = data.key || {};
const event = String(body.event || '').trim();
const fromMe = key.fromMe === true || data.fromMe === true;
const remoteJid = String(key.remoteJid || key.remoteJidAlt || data.remoteJid || '').trim();
const msg = data.message || {};
const texto = msg.conversation || msg.extendedTextMessage?.text || msg.imageMessage?.caption || msg.videoMessage?.caption || msg.documentMessage?.caption || '';
const audioUrl = msg.audioMessage?.url || msg.pttMessage?.url || null;
const textoLimpo = String(texto || '').trim();
const hasAudio = Boolean(audioUrl);
const status = String(data.status || '').trim();
const isMessageUpsert = event === 'messages.upsert';
const isAckOnly = !textoLimpo && !hasAudio && !!status;
const isGroup = remoteJid.endsWith('@g.us');
const evento_valido = Boolean(isMessageUpsert && !fromMe && !isGroup && !isAckOnly && (textoLimpo.length > 0 || hasAudio));
const jidDigits = normalizeBrPhoneDigits(remoteJid.replace(/@.*$/, ''));

return [{ json: {
  ...req,
  evento_valido,
  has_audio: hasAudio,
  audio_url: audioUrl,
  phone_e164: jidDigits ? `+${jidDigits}` : '',
  message_id: key.id ?? `wa-${Date.now()}`,
  text: textoLimpo,
  contact_name: data.pushName ?? '',
  webhook_meta: { event, fromMe, remoteJid, status, hasText: textoLimpo.length > 0, hasAudio, isAckOnly, isGroup },
} }];

const prep = $input.first().json;
const openaiKey = ($env.OPENAI_API_KEY || '').trim();
let text = String(prep.text || '').trim();
let transcribed = String(prep.transcribed_text || '').trim();

if (!text && !transcribed && prep.has_audio && prep.audio_url && openaiKey) {
  try {
    const audioRes = await this.helpers.httpRequest({ method: 'GET', url: prep.audio_url, encoding: 'arraybuffer', returnFullResponse: true });
    const buffer = Buffer.from(audioRes.body);
    const form = new FormData();
    form.append('file', new Blob([buffer], { type: 'audio/ogg' }), 'audio.ogg');
    form.append('model', 'whisper-1');
    form.append('language', 'pt');
    const whisper = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.OPENAI_API_URL || 'https://api.openai.com/v1/audio/transcriptions',
      headers: { Authorization: `Bearer ${openaiKey}` },
      body: form,
      json: true,
    });
    transcribed = String(whisper.text || '').trim();
  } catch (e) {
    transcribed = '';
  }
}

return [{ json: { ...prep, text, transcribed_text: transcribed } }];

function normalizeBrPhoneDigits(raw) {
  let d = String(raw || '').replace(/\D/g, '');
  if (!d) return '';
  if ((d.length === 10 || d.length === 11) && !d.startsWith('55')) d = '55' + d;
  return d;
}

const prep = $input.first().json;
const digits = normalizeBrPhoneDigits(prep.phone_e164 || '');
return [{ json: {
  ...prep,
  phone_e164: digits ? `+${digits}` : prep.phone_e164,
  sender_phone_e164: digits ? `+${digits}` : prep.phone_e164,
  evolution_number: digits,
  phone_identified: digits.length >= 10,
} }];

const item = $input.first().json;
let reason = 'ignored';
let reply_text = '';
const digits = String(item.evolution_number || item.phone_e164 || '').replace(/\D/g, '');
if (item.evento_valido === false) {
  reason = 'invalid_event';
} else if (digits.length < 10) {
  reason = 'missing_phone';
  reply_text = 'Não consegui identificar seu número de WhatsApp. Envie a mensagem novamente.';
}
return [{ json: {
  ignored: true,
  skip_reason: reason,
  session_id: null,
  emitted: false,
  send_reply: reply_text.length > 0,
  reply_text,
  evolution_number: digits,
  phone_e164: item.phone_e164,
} }];

const row = $input.first().json;
const inbound = {
  phone_e164: row.phone_e164,
  message_id: row.message_id,
  text: String(row.text || ''),
  contact_name: String(row.contact_name || ''),
};
const transcribed = String(row.transcribed_text || '').trim();
if (transcribed) inbound.transcribed_text = transcribed;
return [{ json: { ...row, ...inbound, has_audio: row.has_audio === true } }];

const prep = $input.first().json;
const base = String($env.EXEQ_API_BASE_URL || 'http://host.docker.internal:3002').replace(/\/$/, '');
const tenant = $env.EXEQ_TENANT_SLUG || 'piloto-sp';
const token = $env.EXEQ_CHANNEL_TOKEN || 'sandbox-channel-token-piloto';
try {
  const body = await this.helpers.httpRequest({
    method: 'POST',
    url: `${base}/v1/channel/inbound`,
    headers: {
      'x-tenant-slug': tenant,
      'x-channel-token': token,
      'content-type': 'application/json',
    },
    body: {
      phone_e164: prep.phone_e164,
      message_id: prep.message_id,
      text: prep.text || '',
      contact_name: prep.contact_name || '',
      ...(String(prep.transcribed_text || '').trim()
        ? { transcribed_text: String(prep.transcribed_text).trim() }
        : {}),
    },
    json: true,
  });
  const reply = String(body.reply_text || '').trim();
  const sendReply = body.send_reply !== false && reply.length > 0;
  return [{ json: {
    ...body,
    phone_e164: prep.phone_e164,
    reply_text: reply,
    send_reply: sendReply,
    buffered: body.buffered === true,
    debounce_message_count: body.debounce_message_count ?? null,
    evolution_number: String(prep.phone_e164 || '').replace(/\D/g, ''),
    prep_has_audio: prep.has_audio === true,
  }}];
} catch (e) {
  return [{ json: {
    session_id: null,
    emitted: false,
    phone_e164: prep.phone_e164,
    reply_text: 'Não consegui contactar a API Core (host.docker.internal:3002).',
    send_reply: true,
    buffered: false,
    evolution_number: String(prep.phone_e164 || '').replace(/\D/g, ''),
  }}];
}

const prep = $('Montar Body Inbound').first().json;
const raw = $input.first().json ?? {};
const api = raw.session_id != null || raw.buffered === true ? raw : (raw.body && typeof raw.body === 'object' ? raw.body : raw);
let reply = String(api.reply_text || '').trim();
if (api.buffered === true) {
  return [{ json: {
    ...api,
    phone_e164: prep.phone_e164,
    reply_text: '',
    send_reply: false,
    buffered: true,
    evolution_number: String(prep.phone_e164 || '').replace(/\D/g, ''),
  }}];
}
if (!reply && prep.has_audio) {
  reply = 'Recebi seu áudio. Para transcrição automática, configure OPENAI_API_KEY no n8n. Por ora, envie os dados em texto (ex.: R$ 1,00 serviço: consultoria).';
}
if (!reply && Number(raw.statusCode) >= 400) {
  reply = String(api.message || api.error || `Erro HTTP ${raw.statusCode} na API Core`);
}
if (!reply && !api.session_id && api.buffered !== true) {
  reply = 'Não consegui processar sua mensagem na API Core. Verifique se a API está no ar (porta 3002).';
}
const send_reply = api.send_reply !== false && reply.length > 0;
const evolution_number = String(prep.phone_e164 || '').replace(/\D/g, '');
return [{ json: { ...api, phone_e164: prep.phone_e164, reply_text: reply, send_reply, buffered: api.buffered === true, evolution_number } }];

const item = $input.first().json;
const evolutionUrl = String($env.EVOLUTION_API_URL || 'http://evolution:8080').replace(/\/$/, '');
const instance = $env.EVOLUTION_INSTANCE || 'exeq-nfse-core';
const apiKey = $env.EVOLUTION_API_KEY || '';
const number = String(item.evolution_number || '').replace(/\D/g, '');
const text = String(item.reply_text || '').trim();
if (!number || !text) {
  return [{ json: { ...item, evolution_sent: false, evolution_skip: 'missing number or text' } }];
}
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${evolutionUrl}/message/sendText/${encodeURIComponent(instance)}`,
    headers: { apikey: apiKey, 'content-type': 'application/json' },
    body: { number, text },
    json: true,
  });
  return [{ json: { ...item, evolution_sent: true } }];
} catch (e) {
  return [{ json: { ...item, evolution_sent: false, evolution_error: String(e.message || e) } }];
}

const item = $input.first().json;
return [{
  json: {
    ok: true,
    ignored: item.ignored ?? false,
    reason: item.skip_reason ?? item.debounce_reason ?? null,
    session_id: item.session_id ?? null,
    status: item.status ?? null,
    reply_text: item.reply_text ?? null,
    issue_id: item.issue_id ?? null,
    emitted: item.emitted ?? false,
    send_reply: item.send_reply ?? false,
    buffered: item.buffered ?? false,
    debounce_message_count: item.debounce_message_count ?? null,
  },
}];

const base = String($env.EXEQ_API_BASE_URL || 'http://host.docker.internal:3002').replace(/\/$/, '');
const tenant = $env.EXEQ_TENANT_SLUG || 'piloto-sp';
const token = $env.EXEQ_CHANNEL_TOKEN || 'sandbox-channel-token-piloto';
const url = `${base}/v1/channel/notifications/pending?limit=20`;
try {
  const body = await this.helpers.httpRequest({
    method: 'GET',
    url,
    headers: { 'x-tenant-slug': tenant, 'x-channel-token': token },
    json: true,
  });
  return [{ json: { statusCode: 200, body, api_url: url } }];
} catch (e) {
  const statusCode = e.statusCode || e.response?.statusCode || 0;
  return [{ json: {
    statusCode,
    error: String(e.message || e),
    body: { items: [] },
    api_url: url,
  }}];
}

const raw = $input.first().json ?? {};
const statusCode = Number(raw.statusCode ?? raw.status ?? 200);
const apiError = raw.error ? String(raw.error) : null;
const body = raw.body && typeof raw.body === 'object' ? raw.body : raw;
const items = Array.isArray(body.items) ? body.items : [];
const filtered = items.filter((i) => i?.id && i?.phone_e164 && i?.message_body);
const apiOk = statusCode >= 200 && statusCode < 300 && !apiError;
let hint = null;
if (apiError) hint = `Erro ao consultar pending: ${apiError} (${raw.api_url || 'url desconhecida'})`;
else if (filtered.length === 0) hint = 'Sem notificacoes pendentes — normal durante coleta de dados ou enquanto emissao processa (authorized/rejected)';
return [{
  json: {
    api_ok: apiOk,
    status_code: statusCode,
    api_url: raw.api_url ?? null,
    api_error: apiError,
    pending_total: items.length,
    pending_filtered: filtered.length,
    has_pending: filtered.length > 0,
    items: filtered,
    hint,
  },
}];

const batch = $input.first().json ?? {};
return [{ json: {
  ok: true,
  action: 'skip_poll',
  api_ok: batch.api_ok !== false,
  api_error: batch.api_error ?? null,
  pending_total: batch.pending_total ?? 0,
  pending_filtered: batch.pending_filtered ?? 0,
  hint: batch.hint ?? 'Sem notificacoes pendentes — fluxo encerrado normalmente (aguardar proximo poll)',
}}];

const batch = $input.first().json;
const items = Array.isArray(batch.items) ? batch.items : [];
return items.map((i) => ({
  json: {
    ...i,
    evolution_number: String(i.phone_e164 || '').replace(/\D/g, ''),
  },
}));

const item = $input.first().json;
const evolutionUrl = String($env.EVOLUTION_API_URL || 'http://evolution:8080').replace(/\/$/, '');
const instance = $env.EVOLUTION_INSTANCE || 'exeq-nfse-core';
const apiKey = $env.EVOLUTION_API_KEY || '';
const number = String(item.evolution_number || '').replace(/\D/g, '');
const text = String(item.message_body || '').trim();
if (!number || !text) {
  return [{ json: { ...item, evolution_sent: false, evolution_skip: 'missing number or message_body' } }];
}
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url: `${evolutionUrl}/message/sendText/${encodeURIComponent(instance)}`,
    headers: { apikey: apiKey, 'content-type': 'application/json' },
    body: { number, text },
    json: true,
  });
  return [{ json: { ...item, evolution_sent: true } }];
} catch (e) {
  return [{ json: { ...item, evolution_sent: false, evolution_error: String(e.message || e) } }];
}

const notif = $input.first().json;
const base = String($env.EXEQ_API_BASE_URL || 'http://host.docker.internal:3002').replace(/\/$/, '');
const tenant = $env.EXEQ_TENANT_SLUG || 'piloto-sp';
const token = $env.EXEQ_CHANNEL_TOKEN || 'sandbox-channel-token-piloto';
const url = `${base}/v1/channel/notifications/${notif.id}/ack`;
try {
  await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: { 'x-tenant-slug': tenant, 'x-channel-token': token, 'content-type': 'application/json' },
    body: {},
    json: true,
  });
  return [{ json: { acked: true, id: notif.id, phone_e164: notif.phone_e164, api_url: url } }];
} catch (e) {
  return [{ json: { acked: false, id: notif.id, error: String(e.message || e), api_url: url } }];
}
